function Logo({ variant = "green", height = 28 }) {
  const src = variant === "white" ? LOGO_WHITE : LOGO_GREEN;
  return (
    <img
      src={src}
      alt="DGF 25 anos"
      style={{
        height: `${height}px`,
        width: "auto",
        display: "block",
        userSelect: "none",
        pointerEvents: "none"
      }}
      draggable={false}
    />
  );
}

